{"command": "# Check if Rork has synced our commit to GitHub yet
curl -sS "https://api.github.com/repos/ibb142/rork-global-real-estate-invest/commits?sha=main&per_page=3" 2>&1 | python3 -c "
import sys, json
d = json.load(sys.stdin)
if isinstance(d, list):
    for c in d[:3]:
        sha = c.get('sha','?')[:8]
        msg = c.get('commit',{}).get('message','?')[:80]
        date = c.get('commit',{}).get('committer',{}).get('date','?')
        print(f'{sha} {date} {msg}')
else:
    print(f'Error: {d.get(\"message\",\"unknown\")}')
" 2>/dev/null"}

